typedef struct _PRINT_OTHER_INFO {
DWORD alrtpr_jobid;   DWORD alrtpr_status;
DWORD alrtpr_submitted;   DWORD alrtpr_size;
} PRINT_OTHER_INFO, *PPRINT_OTHER_INFO, *LPPRINT_OTHER_INFO;
成员 alrtpr_jobid 类型：DWORD
打印作业的标识号。
alrtpr_status 类型：DWORD
描述打印作业状态的位掩码。
可以通过检查PRJOB_QSTATUS (位 0 和 1) 来获取作业的总体状态。 Lmalert.h 头文件中列出了打印作业状态的可能值。
值

typedef struct _SERVER_INFO_100 {
DWORD sv100_platform_id;   LMSTR sv100_name;
} SERVER_INFO_100, *PSERVER_INFO_100, *LPSERVER_INFO_100; 成员
sv100_platform_id 类型：DWORD
用于特定于平台的信息的信息级别。
Lmcons.h 头文件中列出了此成员的可能值。
值

typedef struct _SERVER_INFO_1005 {   LMSTR sv1005_comment;
} SERVER_INFO_1005, *PSERVER_INFO_1005, *LPSERVER_INFO_1005; 成员
sv1005_comment
指向包含描述服务器的注释的字符串的指针。 注释可以为 null。
如果定义了 _WIN32_WINNT 或 FORCE_UNICODE ，则此字符串为 Unicode。

typedef struct _SERVER_INFO_101 {
DWORD sv101_platform_id;   LMSTR sv101_name;
DWORD sv101_version_major;   DWORD sv101_version_minor;   DWORD sv101_type;
LMSTR sv101_comment;
} SERVER_INFO_101, *PSERVER_INFO_101, *LPSERVER_INFO_101; 成员
sv101_platform_id 类型：DWORD
用于特定于平台的信息的信息级别。
Lmcons.h 头文件中列出了此成员的可能值。
值

typedef struct _SERVER_INFO_1010 {   LONG sv1010_disc;
} SERVER_INFO_1010, *PSERVER_INFO_1010, *LPSERVER_INFO_1010;
成员 sv1010_disc
指定自动断开连接时间（以分钟为单位）。
如果会话的空闲时间长于此成员指定的时间段，则服务器会断开该会话的连接。 如果此
成员的值为 SV_NODISC，则不会启用自动断开连接。

typedef struct _SERVER_INFO_1016 {   BOOL sv1016_hidden;
} SERVER_INFO_1016, *PSERVER_INFO_1016, *LPSERVER_INFO_1016;
成员 sv1016_hidden
指定服务器是否对同一网络域中的其他计算机可见。 此成员可以是以下值之一。
值

typedef struct _SERVER_INFO_1017 {   DWORD sv1017_announce;
} SERVER_INFO_1017, *PSERVER_INFO_1017, *LPSERVER_INFO_1017; 成员
sv1017_announce
指定网络报出速率（以秒为单位）。 此速率确定向网络上的其他计算机宣布服务器的频率。
有关公告速率随此成员指定的时间段而异的详细信息，请参阅 SERVER_INFO_1018。

typedef struct _SERVER_INFO_102 {
DWORD sv102_platform_id;   LMSTR sv102_name;
DWORD sv102_version_major;   DWORD sv102_version_minor;   DWORD sv102_type;
LMSTR sv102_comment;   DWORD sv102_users;   LONG  sv102_disc;   BOOL  sv102_hidden;
DWORD sv102_announce;   DWORD sv102_anndelta;   DWORD sv102_licenses;   LMSTR sv102_userpath;
} SERVER_INFO_102, *PSERVER_INFO_102, *LPSERVER_INFO_102; 成员
sv102_platform_id 类型：DWORD
用于特定于平台的信息的信息级别。
Lmcons.h 头文件中列出了此成员的可能值。
值

typedef struct _SERVER_INFO_1107 {   DWORD sv1107_users;
} SERVER_INFO_1107, *PSERVER_INFO_1107, *LPSERVER_INFO_1107;
成员 sv1107_users
指定可以尝试登录到系统服务器的用户数。 请注意，许可证服务器决定了这些用户可以
实际登录的数量。

typedef struct _SERVER_INFO_1501 {   DWORD sv1501_sessopens;
} SERVER_INFO_1501, *PSERVER_INFO_1501, *LPSERVER_INFO_1501; 成员
sv1501_sessopens
指定一个会话可以打开的文件数。

typedef struct _SERVER_INFO_1502 {   DWORD sv1502_sessvcs;
} SERVER_INFO_1502, *PSERVER_INFO_1502, *LPSERVER_INFO_1502; 成员
sv1502_sessvcs
指定每个客户端允许的最大虚拟线路数。

typedef struct _SERVER_INFO_1503 {   DWORD sv1503_opensearch;
} SERVER_INFO_1503, *PSERVER_INFO_1503, *LPSERVER_INFO_1503; 成员
sv1503_opensearch
指定可以同时执行的搜索操作数。

typedef struct _SERVER_INFO_1506 {   DWORD sv1506_maxworkitems;
} SERVER_INFO_1506, *PSERVER_INFO_1506, *LPSERVER_INFO_1506; 成员
sv1506_maxworkitems
指定服务器可以分配的最大接收缓冲区数或工作项。 如果达到此限制，则传输协议必须
启动流控制，但对性能有重大影响。

typedef struct _SERVER_INFO_1509 {   DWORD sv1509_maxrawbuflen;
} SERVER_INFO_1509, *PSERVER_INFO_1509, *LPSERVER_INFO_1509; 成员
sv1509_maxrawbuflen
指定原始模式缓冲区的最大大小（以字节为单位）。

typedef struct _SERVER_INFO_1510 {
DWORD sv1510_sessusers;
} SERVER_INFO_1510, *PSERVER_INFO_1510, *LPSERVER_INFO_1510;

typedef struct _SERVER_INFO_1511 {   DWORD sv1511_sessconns;
} SERVER_INFO_1511, *PSERVER_INFO_1511, *LPSERVER_INFO_1511; 成员
sv1511_sessconns
指定用户可以使用单个虚拟线路建立的最大树连接数。

typedef struct _SERVER_INFO_1512 {
DWORD sv1512_maxnonpagedmemoryusage;
} SERVER_INFO_1512, *PSERVER_INFO_1512, *LPSERVER_INFO_1512; 成员
sv1512_maxnonpagedmemoryusage
指定服务器一次可以分配的非分页内存的最大大小。 如果要管理内存配额控制，请调整
此成员。

typedef struct _SERVER_INFO_1513 {   DWORD sv1513_maxpagedmemoryusage;
} SERVER_INFO_1513, *PSERVER_INFO_1513, *LPSERVER_INFO_1513; 成员
sv1513_maxpagedmemoryusage
指定服务器在任何特定时间分配的可分页内存的最大大小。 如果要管理内存配额控制，
请调整此成员。

typedef struct _SERVER_INFO_1515 {   BOOL sv1515_enableforcedlogoff;
} SERVER_INFO_1515, *PSERVER_INFO_1515, *LPSERVER_INFO_1515; 成员
sv1515_enableforcedlogoff
指定在客户端登录时间过期后，服务器是否应强制客户端断开连接（即使客户端有打开的
文件）。

typedef struct _SERVER_INFO_1516 {   BOOL sv1516_timesource;
} SERVER_INFO_1516, *PSERVER_INFO_1516, *LPSERVER_INFO_1516; 成员
sv1516_timesource
指定服务器是否为可靠的时间源。

typedef struct _SERVER_INFO_1518 {   BOOL sv1518_lmannounce;
} SERVER_INFO_1518, *PSERVER_INFO_1518, *LPSERVER_INFO_1518; 成员
sv1518_lmannounce
指定服务器是否对 LAN Manager 2 可见。x 客户端。

typedef struct _SERVER_INFO_1523 {   DWORD sv1523_maxkeepsearch;
} SERVER_INFO_1523, *PSERVER_INFO_1523, *LPSERVER_INFO_1523; 成员
sv1523_maxkeepsearch
指定服务器保留有关不完整搜索操作的信息的时间长度。

typedef struct _SERVER_INFO_1528 {   DWORD sv1528_scavtimeout;
} SERVER_INFO_1528, *PSERVER_INFO_1528, *LPSERVER_INFO_1528; 成员
sv1528_scavtimeout
指定清除器在唤醒服务请求之前保持空闲的时间段（以秒为单位）。 此成员的较小值可
改善服务器对各种事件的响应，但会消耗 CPU 周期。

typedef struct _SERVER_INFO_1529 {   DWORD sv1529_minrcvqueue;
} SERVER_INFO_1529, *PSERVER_INFO_1529, *LPSERVER_INFO_1529; 成员
sv1529_minrcvqueue
指定服务器在开始分配更多工作项之前所需的最小免费接收工作项数。 此成员的较大值
有助于确保始终有可用的工作项，但值过大会效率低下。

typedef struct _SERVER_INFO_1530 {   DWORD sv1530_minfreeworkitems;
